 28→// makeXZ compresses data using the system xz binary and returns the compressed bytes.
 29→func makeXZ(t *testing.T, data string) []byte {
 30→	t.Helper()
 31→	var buf bytes.Buffer
 32→	cmd := exec.Command("xz", "-c") //nolint:gosec
 33→	cmd.Stdin = strings.NewReader(data)
 34→	cmd.Stdout = &buf
 35→	if err := cmd.Run(); err != nil {
 36→		t.Fatalf("makeXZ: %v", err)
 37→	}
 38→	return buf.Bytes()
 39→}
