207→	}
208→	defer pool.Close()
209→
210→	m, err := Load(ctx, pool)
211→	if err != nil {
212→		t.Fatalf("Load: %v", err)
213→	}
214→
215→	// Verify basic stats — we should have loaded something
216→	if len(m.exact) == 0 {
217→		t.Error("exact map is empty — no institutions loaded")
218→	}
219→	if len(m.ope6) == 0 {
220→		t.Error("ope6 map is empty")
221→	}
222→
223→	// Spot-check a known canonical name if it exists in the DB.
224→	// Harvard (unit_id 166027) should always be present in NCES data.
225→	uid, ok := m.Match("Harvard University")
226→	if ok {
227→		t.Logf("Harvard University → unit_id %q", uid)
228→	}
