429→		_, _ = pool.Exec(ctx, "DELETE FROM search_base.institution WHERE unit_id = $1", testUnitID)
430→	})
431→
432→	// Insert two dataset rows in a single batch.
433→	const insertSQL = `
434→		INSERT INTO search_base.dataset (id, unit_id, theme, datakey, data, created, updated, version)
435→		VALUES ($1, $2, $3, $4, $5, now(), now(), 1)
436→		ON CONFLICT (id) DO NOTHING`
437→
438→	queries := []BatchQuery{
439→		{SQL: insertSQL, Args: []any{
440→			datasetID(testUnitID, "COST", "tuition"), testUnitID, "COST", "tuition", []byte(`{"in_state":10000}`),
441→		}},
442→		{SQL: insertSQL, Args: []any{
443→			datasetID(testUnitID, "COST", "fees"), testUnitID, "COST", "fees", []byte(`{"amount":500}`),
444→		}},
445→	}
446→
447→	if err := BatchExec(ctx, pool, queries); err != nil {
448→		t.Fatalf("BatchExec: %v", err)
449→	}
450→
451→	var count int
452→	if err := pool.QueryRow(ctx,
453→		"SELECT COUNT(*) FROM search_base.dataset WHERE unit_id = $1", testUnitID,
454→	).Scan(&count); err != nil {
455→		t.Fatalf("count query: %v", err)
456→	}
457→	if count != 2 {
458→		t.Errorf("expected 2 rows, got %d", count)
459→	}
460→}
