  1→package ranking
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"log/slog"
  8→	"math"
  9→	"strconv"
 10→	"strings"
 11→
 12→	"github.com/jackc/pgx/v5/pgxpool"
 13→	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
 14→)
 15→
 16→// Opinion represents a single ranking observation for one institution from one
 17→// publication/category in a given year.
 18→type Opinion struct {
 19→	PublicationSlug string
 20→	CategorySlug    string
 21→	Method          string  // "rank", "score", "tier", "range"
 22→	Year            int
 23→	UnitID          string
 24→	Rank            int
 25→	Score           float64
 26→	Tier            string
 27→}
 28→
 29→// PublicationMeta holds display metadata for a ranking publication+category.
 30→type PublicationMeta struct {
 31→	PublicationSlug string
 32→	Publication     string // display name
 33→	CategorySlug    string
 34→	Category        string // display name
 35→	URL             string
 36→}
 37→
 38→// rankingID returns the deterministic key used across ranking tables and the
 39→// institution JSONB column. Format: "pub_slug____cat_slug".
 40→func rankingID(pubSlug, catSlug string) string {
 41→	return pubSlug + "____" + catSlug
 42→}
 43→
 44→// RankingBuilder accumulates Opinion values and publication metadata, then
 45→// batch-writes them to the database via Flush.
 46→type RankingBuilder struct {
 47→	opinions     []Opinion
 48→	publications map[string]PublicationMeta // keyed by rankingID
 49→}
 50→
 51→// NewBuilder creates an empty RankingBuilder.
 52→func NewBuilder() *RankingBuilder {
 53→	return &RankingBuilder{
 54→		publications: make(map[string]PublicationMeta),
 55→	}
 56→}
 57→
 58→// SetPublication registers display metadata for a publication+category pair.
 59→func (b *RankingBuilder) SetPublication(pubSlug, pubName, catSlug, catName, url string) {
 60→	id := rankingID(pubSlug, catSlug)
 61→	b.publications[id] = PublicationMeta{
 62→		PublicationSlug: pubSlug,
 63→		Publication:     pubName,
 64→		CategorySlug:    catSlug,
 65→		Category:        catName,
 66→		URL:             url,
 67→	}
 68→}
 69→
 70→// Add appends an opinion to the builder.
 71→func (b *RankingBuilder) Add(op Opinion) {
 72→	b.opinions = append(b.opinions, op)
 73→}
 74→
 75→// Len returns the number of accumulated opinions.
 76→func (b *RankingBuilder) Len() int {
 77→	return len(b.opinions)
 78→}
 79→
 80→// Flush writes all accumulated data to the database:
 81→//  1. Upserts ranking metadata into search_base.ranking
 82→//  2. Upserts per-year data into search_base.annual_dataset (theme=RANKING)
 83→//  3. Merges latest-year rankings into institution.rankings JSONB
 84→func (b *RankingBuilder) Flush(ctx context.Context, pool *pgxpool.Pool) error {
 85→	if len(b.opinions) == 0 {
 86→		return nil
 87→	}
 88→
 89→	// Step 1: upsert ranking metadata
 90→	if err := b.flushRankingMeta(ctx, pool); err != nil {
 91→		return err
 92→	}
 93→
 94→	// Step 2: upsert annual datasets
 95→	if err := b.flushAnnualDatasets(ctx, pool); err != nil {
 96→		return err
 97→	}
 98→
 99→	// Step 3: merge into institution.rankings JSONB
100→	if err := b.flushInstitutionRankings(ctx, pool); err != nil {
101→		return err
102→	}
103→
104→	slog.Info("ranking: flushed", "opinions", len(b.opinions), "publications", len(b.publications))
105→	return nil
106→}
107→
108→func (b *RankingBuilder) flushRankingMeta(ctx context.Context, pool *pgxpool.Pool) error {
109→	const upsertSQL = `
110→INSERT INTO search_base.ranking (id, publication_slug, publication, category_slug, category, url)
111→VALUES ($1, $2, $3, $4, $5, $6)
112→ON CONFLICT (id) DO UPDATE SET
113→    publication = EXCLUDED.publication,
114→    category    = EXCLUDED.category,
115→    url         = EXCLUDED.url`
116→
117→	queries := make([]dbutil.BatchQuery, 0, len(b.publications))
118→	for id, pm := range b.publications {
119→		queries = append(queries, dbutil.BatchQuery{
120→			SQL:  upsertSQL,
121→			Args: []any{id, pm.PublicationSlug, pm.Publication, pm.CategorySlug, pm.Category, pm.URL},
122→		})
123→	}
124→	if err := dbutil.BatchExec(ctx, pool, queries); err != nil {
125→		return fmt.Errorf("ranking: flush ranking meta: %w", err)
126→	}
127→	return nil
128→}
129→
130→func (b *RankingBuilder) flushAnnualDatasets(ctx context.Context, pool *pgxpool.Pool) error {
131→	const batchSize = 500
132→	for i := 0; i < len(b.opinions); i += batchSize {
133→		end := i + batchSize
134→		if end > len(b.opinions) {
135→			end = len(b.opinions)
136→		}
137→		if err := b.flushAnnualDatasetBatch(ctx, pool, b.opinions[i:end]); err != nil {
138→			return err
139→		}
140→	}
141→	return nil
142→}
143→
144→func (b *RankingBuilder) flushAnnualDatasetBatch(ctx context.Context, pool *pgxpool.Pool, opinions []Opinion) error {
145→	for _, op := range opinions {
146→		data := buildOpinionData(op)
147→		dataJSON, err := json.Marshal(data)
148→		if err != nil {
149→			return fmt.Errorf("ranking: marshal annual dataset: %w", err)
150→		}
151→		ads := &dbutil.AnnualDataset{
152→			UnitID:  op.UnitID,
153→			Year:    op.Year,
154→			Theme:   "RANKING",
155→			Datakey: rankingID(op.PublicationSlug, op.CategorySlug),
156→			Data:    dataJSON,
157→		}
158→		if err := dbutil.UpsertAnnualDataset(ctx, pool, ads); err != nil {
159→			return fmt.Errorf("ranking: flush annual dataset: %w", err)
160→		}
161→	}
162→	return nil
163→}
164→
165→// buildOpinionData returns the JSONB payload for an opinion.
166→func buildOpinionData(op Opinion) map[string]any {
167→	d := map[string]any{
168→		"method": op.Method,
169→	}
170→	switch op.Method {
171→	case "rank":
172→		d["rank"] = op.Rank
173→	case "score":
174→		d["score"] = op.Score
175→	case "tier":
176→		d["tier"] = op.Tier
177→	case "range":
178→		d["rank"] = op.Rank
179→		d["tier"] = op.Tier
180→	}
181→	return d
182→}
183→
184→func (b *RankingBuilder) flushInstitutionRankings(ctx context.Context, pool *pgxpool.Pool) error {
185→	// Group opinions by unit_id, keeping only the latest year per ranking.
186→	type key struct {
187→		unitID    string
188→		rankingID string
189→	}
190→	latest := make(map[key]Opinion)
191→	for _, op := range b.opinions {
192→		k := key{unitID: op.UnitID, rankingID: rankingID(op.PublicationSlug, op.CategorySlug)}
193→		if existing, ok := latest[k]; !ok || op.Year > existing.Year {
194→			latest[k] = op
195→		}
196→	}
197→
198→	// Group by unit_id to build per-institution JSONB.
199→	byUnit := make(map[string]map[string]any)
200→	for k, op := range latest {
201→		if byUnit[k.unitID] == nil {
202→			byUnit[k.unitID] = make(map[string]any)
203→		}
204→		byUnit[k.unitID][k.rankingID] = buildOpinionData(op)
205→	}
206→
207→	for unitID, rankings := range byUnit {
208→		rankingsJSON, err := json.Marshal(rankings)
209→		if err != nil {
210→			return fmt.Errorf("ranking: marshal institution rankings: %w", err)
211→		}
212→		inst := &dbutil.Institution{
213→			UnitID:   unitID,
214→			Rankings: rankingsJSON,
215→		}
216→		if err := dbutil.UpsertInstitution(ctx, pool, inst); err != nil {
217→			return fmt.Errorf("ranking: flush institution rankings: %w", err)
218→		}
219→	}
220→	return nil
221→}
222→
223→// DeriveOpinion parses a raw ranking string and returns the method, rank,
224→// score, and tier. Supported formats:
225→//   - Numeric ranks: "1", "42"
226→//   - Tier strings: "Tier 1", "Tier 2"
227→//   - Ranges: "201-300" (rank = midpoint, tier = original string)
228→//   - Decimal scores: "78.5"
229→func DeriveOpinion(raw string) (method string, rank int, score float64, tier string, err error) {
230→	raw = strings.TrimSpace(raw)
231→	if raw == "" {
232→		return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: empty input")
233→	}
234→
235→	// Tier format: "Tier N" or "Tier ..."
236→	if strings.HasPrefix(strings.ToLower(raw), "tier") {
237→		return "tier", 0, 0, raw, nil
238→	}
239→
240→	// Range format: "NNN-NNN"
241→	if parts := strings.SplitN(raw, "-", 2); len(parts) == 2 {
242→		lo, errLo := strconv.Atoi(strings.TrimSpace(parts[0]))
243→		hi, errHi := strconv.Atoi(strings.TrimSpace(parts[1]))
244→		if errLo == nil && errHi == nil && lo > 0 && hi > 0 {
245→			midpoint := int(math.Round(float64(lo+hi) / 2))
246→			return "range", midpoint, 0, raw, nil
247→		}
248→	}
249→
250→	// Integer rank
251→	if n, errInt := strconv.Atoi(raw); errInt == nil {
252→		return "rank", n, 0, "", nil
253→	}
254→
255→	// Decimal score
256→	if f, errFloat := strconv.ParseFloat(raw, 64); errFloat == nil {
257→		return "score", 0, f, "", nil
258→	}
259→
260→	return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: unrecognized format %q", raw)
261→}
