package scraper

import (
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

// Sentinel errors for cache operations.
var (
	ErrNotFound = errors.New("scraper: cache entry not found")
	ErrStale    = errors.New("scraper: cache entry is stale")
)

// cacheEntry is the JSON structure stored on disk.
type cacheEntry struct {
	ScrapedAt    string   `json:"scraped_at"`
	Institutions []string `json:"institutions"`
}

// Cache stores and retrieves scraped institution name lists as JSON files.
type Cache struct {
	dir    string
	maxAge time.Duration
}

// NewCache creates a cache that stores files under dir with the given
// staleness threshold.
func NewCache(dir string, maxAge time.Duration) *Cache {
	return &Cache{dir: dir, maxAge: maxAge}
}

// cacheDir returns the directory for admissions cache files.
func (c *Cache) cacheDir() string {
	return filepath.Join(c.dir, "admissions")
}

// filename returns the cache file path for a platform and date.
func (c *Cache) filename(platform string, date time.Time) string {
	return filepath.Join(c.cacheDir(), fmt.Sprintf("%s-%s.json", platform, date.Format("2006-01-02")))
}

// Save writes the institution names to a dated cache file.
func (c *Cache) Save(platform string, names []string) error {
	dir := c.cacheDir()
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("scraper: cache mkdir: %w", err)
	}

	now := time.Now()
	entry := cacheEntry{
		ScrapedAt:    now.Format(time.RFC3339),
		Institutions: names,
	}

	data, err := json.MarshalIndent(entry, "", "  ")
	if err != nil {
		return fmt.Errorf("scraper: cache marshal: %w", err)
	}

	path := c.filename(platform, now)
	if err := os.WriteFile(path, data, 0o644); err != nil {
		return fmt.Errorf("scraper: cache write: %w", err)
	}
	return nil
}

// Load reads the most recent cache file for the given platform. Returns
// ErrNotFound if no file exists, or ErrStale if the newest file is older
// than maxAge.
func (c *Cache) Load(platform string) ([]string, error) {
	dir := c.cacheDir()
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, ErrNotFound
		}
		return nil, fmt.Errorf("scraper: cache readdir: %w", err)
	}

	// Find the newest matching file by sorting lexically (date in filename).
	prefix := platform + "-"
	var newest string
	for _, e := range entries {
		name := e.Name()
		if len(name) > len(prefix) && name[:len(prefix)] == prefix && filepath.Ext(name) == ".json" {
			if name > newest {
				newest = name
			}
		}
	}
	if newest == "" {
		return nil, ErrNotFound
	}

	path := filepath.Join(dir, newest)
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("scraper: cache read: %w", err)
	}

	var entry cacheEntry
	if err := json.Unmarshal(data, &entry); err != nil {
		return nil, fmt.Errorf("scraper: cache unmarshal: %w", err)
	}

	scrapedAt, err := time.Parse(time.RFC3339, entry.ScrapedAt)
	if err != nil {
		return nil, fmt.Errorf("scraper: cache parse time: %w", err)
	}
	if time.Since(scrapedAt) > c.maxAge {
		return nil, ErrStale
	}

	return entry.Institutions, nil
}

package platform

import "context"

// Browser is satisfied by scraper.Browser (defined in the scraper package).
type Browser interface {
	Navigate(ctx context.Context, url string) error
	EvalStrings(ctx context.Context, jsExpr string) ([]string, error)
}

// Extractor scrapes a college application platform's member list.
type Extractor interface {
	Key() string   // enum value stored in JSONB (e.g. "Common", "CBCA")
	Label() string // human-readable label (e.g. "Common App")
	Extract(ctx context.Context, browser Browser) ([]string, error)
}

// Platform key constants.
const (
	KeyCommon        = "Common"
	KeyCoalition     = "Coalition"
	KeyCBCA          = "CBCA"
	KeyQuestBridge   = "QuestBridge"
	KeyApplyTexas    = "ApplyTexas"
	KeyApplySUNY     = "ApplySUNY"
	KeyUCApplication = "UCApplication"
	KeyCalStateApply = "CalStateApply"
	KeyUWSystem      = "UWSystem"
	KeyApplyIdaho    = "ApplyIdaho"
	KeyGAFutures     = "GAFutures"
	KeyCFNC          = "CFNC"
	KeyFloridaSUS    = "FloridaSUS"
)

// AllKeys returns all platform key constants.
func AllKeys() []string {
	return []string{
		KeyCommon, KeyCoalition, KeyCBCA, KeyQuestBridge,
		KeyApplyTexas, KeyApplySUNY, KeyUCApplication, KeyCalStateApply,
		KeyUWSystem, KeyApplyIdaho, KeyGAFutures, KeyCFNC, KeyFloridaSUS,
	}
}

// All returns all registered extractors.
func All() []Extractor {
	return []Extractor{
		newUCApplication(),
		newCalStateApply(),
		newFloridaSUS(),
	}
}

