package main

import (
	"context"
	"encoding/json"
	"errors"
	"flag"
	"fmt"
	"log/slog"
	"sort"
	"strings"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/tools/kapow/internal/config"
	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
	"github.com/ketang/kapow/tools/kapow/internal/fetch"
	"github.com/ketang/kapow/tools/kapow/internal/namematch"
	"github.com/ketang/kapow/tools/kapow/internal/platform"
	"github.com/ketang/kapow/tools/kapow/internal/scraper"
)

func init() {
	Register(&admissionsImporter{})
}

type admissionsImporter struct {
	maxCacheAge time.Duration
	requireAll  bool
	platforms   string
}

func (a *admissionsImporter) Name() string        { return "admissions" }
func (a *admissionsImporter) Description() string  { return "Import application platform membership data" }
func (a *admissionsImporter) Dependencies() []string { return nil }

func (a *admissionsImporter) RegisterFlags(fs *flag.FlagSet) {
	fs.DurationVar(&a.maxCacheAge, "max-cache-age", 7*24*time.Hour, "maximum cache age before re-scraping")
	fs.BoolVar(&a.requireAll, "require-all", false, "fail if any scraper errors")
	fs.StringVar(&a.platforms, "platforms", "", "comma-separated platform keys to run (default: all)")
}

func (a *admissionsImporter) Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error {
	// Load name matcher from DB.
	matcher, err := namematch.Load(ctx, pool)
	if err != nil {
		return fmt.Errorf("admissions: load matcher: %w", err)
	}

	// Initialize headless browser.
	browser, err := scraper.New()
	if err != nil {
		return fmt.Errorf("admissions: create browser: %w", err)
	}
	defer browser.Close()

	cache := scraper.NewCache(fetcher.CacheDir(), a.maxCacheAge)
	filter := parsePlatformFilter(a.platforms)
	extractors := platform.All()

	// Scrape (or load from cache) each platform.
	platformNames, errs := scrapeAll(ctx, extractors, browser, cache, filter)

	if a.requireAll && len(errs) > 0 {
		return fmt.Errorf("admissions: %d extractor(s) failed: %w", len(errs), errors.Join(errs...))
	}

	// Match names to unit IDs and aggregate platforms per institution.
	admissions, stats := aggregateAdmissions(platformNames, matcher)

	// Log per-platform stats.
	for _, s := range stats {
		slog.Info("admissions: platform stats",
			"platform", s.key,
			"scraped", s.scraped,
			"matched", s.matched,
			"unmatched", s.unmatched,
		)
	}

	// Build JSONB payloads and write to DB.
	bulkData, err := buildAdmissionsJSON(admissions)
	if err != nil {
		return fmt.Errorf("admissions: build json: %w", err)
	}

	if err := dbutil.BulkSetAdmissions(ctx, pool, bulkData); err != nil {
		return fmt.Errorf("admissions: bulk upsert: %w", err)
	}

	slog.Info("admissions: complete", "institutions_updated", len(bulkData))
	return nil
}

// parsePlatformFilter converts a comma-separated string of platform keys into
// a set. An empty string means "all platforms".
func parsePlatformFilter(s string) map[string]bool {
	s = strings.TrimSpace(s)
	if s == "" {
		return nil
	}
	m := make(map[string]bool)
	for _, k := range strings.Split(s, ",") {
		k = strings.TrimSpace(k)
		if k != "" {
			m[k] = true
		}
	}
	return m
}

// scrapeAll runs each extractor (checking cache first) and returns a map of
// platform key → institution names. Errors from individual extractors are
// collected and returned separately.
func scrapeAll(ctx context.Context, extractors []platform.Extractor, browser *scraper.Browser, cache *scraper.Cache, filter map[string]bool) (map[string][]string, []error) {
	result := make(map[string][]string)
	var errs []error

	for _, ext := range extractors {
		key := ext.Key()
		if filter != nil && !filter[key] {
			slog.Debug("admissions: skipping platform (filtered)", "platform", key)
			continue
		}

		names, err := loadOrScrape(ctx, ext, browser, cache)
		if err != nil {
			slog.Warn("admissions: extractor failed", "platform", key, "error", err)
			errs = append(errs, fmt.Errorf("%s: %w", key, err))
			continue
		}

		result[key] = names
		slog.Info("admissions: scraped", "platform", key, "institutions", len(names))
	}

	return result, errs
}

// loadOrScrape attempts to load cached results; on miss or stale, runs the
// extractor and saves the result to cache.
func loadOrScrape(ctx context.Context, ext platform.Extractor, browser *scraper.Browser, cache *scraper.Cache) ([]string, error) {
	names, err := cache.Load(ext.Key())
	if err == nil {
		slog.Debug("admissions: cache hit", "platform", ext.Key(), "institutions", len(names))
		return names, nil
	}

	names, err = ext.Extract(ctx, browser)
	if err != nil {
		return nil, err
	}

	if saveErr := cache.Save(ext.Key(), names); saveErr != nil {
		slog.Warn("admissions: cache save failed", "platform", ext.Key(), "error", saveErr)
	}

	return names, nil
}

// platformStat tracks scrape/match statistics for a single platform.
type platformStat struct {
	key       string
	scraped   int
	matched   int
	unmatched int
}

// aggregateAdmissions matches institution names from each platform to unit IDs
// and builds a map of unitID → sorted platform keys.
func aggregateAdmissions(platformNames map[string][]string, matcher *namematch.Matcher) (map[string][]string, []platformStat) {
	byUnit := make(map[string]map[string]bool)
	var stats []platformStat

