package main

import (
	"context"
	"encoding/json"
	"errors"
	"testing"

	"github.com/ketang/kapow/tools/kapow/internal/namematch"
	"github.com/ketang/kapow/tools/kapow/internal/platform"
	"github.com/ketang/kapow/tools/kapow/internal/scraper"
)

// mockExtractor implements platform.Extractor for testing.
type mockExtractor struct {
	key   string
	label string
	names []string
	err   error
}

func (m *mockExtractor) Key() string   { return m.key }
func (m *mockExtractor) Label() string { return m.label }
func (m *mockExtractor) Extract(_ context.Context, _ platform.Browser) ([]string, error) {
	if m.err != nil {
		return nil, m.err
	}
	return m.names, nil
}

func TestAdmissionsAggregation(t *testing.T) {
	matcher := namematch.NewTestMatcher(map[string]string{
		"harvard university": "100001",
		"mit":                "100002",
		"stanford university": "100003",
	})

	platformNames := map[string][]string{
		"Common":    {"Harvard University", "MIT", "Stanford University"},
		"Coalition": {"Harvard University", "Stanford University"},
	}

	admissions, stats := aggregateAdmissions(platformNames, matcher)

	// Harvard should have both platforms.
	if got := admissions["100001"]; len(got) != 2 || got[0] != "Coalition" || got[1] != "Common" {
		t.Errorf("Harvard platforms = %v, want [Coalition Common]", got)
	}

	// MIT should have only Common.
	if got := admissions["100002"]; len(got) != 1 || got[0] != "Common" {
		t.Errorf("MIT platforms = %v, want [Common]", got)
	}

	// Stanford should have both.
	if got := admissions["100003"]; len(got) != 2 || got[0] != "Coalition" || got[1] != "Common" {
		t.Errorf("Stanford platforms = %v, want [Coalition Common]", got)
	}

	// Stats should be correct.
	if len(stats) != 2 {
		t.Fatalf("stats length = %d, want 2", len(stats))
	}
	for _, s := range stats {
		if s.scraped != len(platformNames[s.key]) {
			t.Errorf("platform %s: scraped = %d, want %d", s.key, s.scraped, len(platformNames[s.key]))
		}
		if s.unmatched != 0 {
			t.Errorf("platform %s: unmatched = %d, want 0", s.key, s.unmatched)
		}
	}
}

func TestAdmissionsAggregationUnmatched(t *testing.T) {
	matcher := namematch.NewTestMatcher(map[string]string{
		"harvard university": "100001",
	})

	platformNames := map[string][]string{
		"Common": {"Harvard University", "Unknown College"},
	}

	admissions, stats := aggregateAdmissions(platformNames, matcher)

	if len(admissions) != 1 {
		t.Errorf("admissions length = %d, want 1", len(admissions))
	}
	if stats[0].matched != 1 || stats[0].unmatched != 1 {
		t.Errorf("stats = matched:%d unmatched:%d, want matched:1 unmatched:1",
			stats[0].matched, stats[0].unmatched)
	}
}

func TestAdmissionsJSONB(t *testing.T) {
	admissions := map[string][]string{
		"100001": {"CBCA", "Common", "QuestBridge"},
	}

	bulkData, err := buildAdmissionsJSON(admissions)
	if err != nil {
		t.Fatalf("buildAdmissionsJSON: %v", err)
	}

	data, ok := bulkData["100001"]
	if !ok {
		t.Fatal("missing 100001 in result")
	}

	var payload admissionsPayload
	if err := json.Unmarshal(data, &payload); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}

	want := []string{"CBCA", "Common", "QuestBridge"}
	if len(payload.Applications) != len(want) {
		t.Fatalf("applications = %v, want %v", payload.Applications, want)
	}
	for i, app := range payload.Applications {
		if app != want[i] {
			t.Errorf("applications[%d] = %q, want %q", i, app, want[i])
		}
	}
}

func TestAdmissionsPartialFailure(t *testing.T) {
	extractors := []platform.Extractor{
		&mockExtractor{key: "Good", label: "Good Platform", names: []string{"Harvard University"}},
		&mockExtractor{key: "Bad", label: "Bad Platform", err: errors.New("network timeout")},
		&mockExtractor{key: "AlsoGood", label: "Also Good", names: []string{"MIT"}},
	}

	cache := scraper.NewCache(t.TempDir(), 0) // maxAge=0 forces miss
	ctx := context.Background()

	result, errs := scrapeAll(ctx, extractors, nil, cache, nil)

	if len(errs) != 1 {
		t.Fatalf("errs = %d, want 1", len(errs))
	}
	if len(result) != 2 {
		t.Fatalf("result platforms = %d, want 2", len(result))
	}
	if _, ok := result["Good"]; !ok {
		t.Error("missing Good platform in result")
	}
	if _, ok := result["AlsoGood"]; !ok {
		t.Error("missing AlsoGood platform in result")
	}
}

func TestAdmissionsRequireAll(t *testing.T) {
	// Verify that scrapeAll collects errors that the caller can check.
	extractors := []platform.Extractor{
		&mockExtractor{key: "Good", label: "Good", names: []string{"Harvard University"}},
		&mockExtractor{key: "Bad", label: "Bad", err: errors.New("timeout")},
	}

	cache := scraper.NewCache(t.TempDir(), 0)
	ctx := context.Background()

	_, errs := scrapeAll(ctx, extractors, nil, cache, nil)

	if len(errs) == 0 {
		t.Fatal("expected errors from failed extractor")
	}

	// Simulate requireAll check (as done in Run).
	combined := errors.Join(errs...)
	if combined == nil {
		t.Fatal("errors.Join returned nil")
	}
}

func TestAdmissionsPlatformFilter(t *testing.T) {
	extractors := []platform.Extractor{
		&mockExtractor{key: "UC", label: "UC", names: []string{"UCLA"}},
		&mockExtractor{key: "CBCA", label: "CBCA", names: []string{"Spelman College"}},
		&mockExtractor{key: "Common", label: "Common", names: []string{"Harvard University"}},
	}

	filter := parsePlatformFilter("UC,CBCA")
	cache := scraper.NewCache(t.TempDir(), 0)
	ctx := context.Background()

	result, errs := scrapeAll(ctx, extractors, nil, cache, filter)

	if len(errs) != 0 {
		t.Fatalf("unexpected errors: %v", errs)
	}
	if len(result) != 2 {
		t.Fatalf("result platforms = %d, want 2", len(result))
	}
	if _, ok := result["UC"]; !ok {
		t.Error("missing UC platform")
	}
	if _, ok := result["CBCA"]; !ok {
		t.Error("missing CBCA platform")
	}
	if _, ok := result["Common"]; ok {
		t.Error("Common should have been filtered out")
	}
}

func TestParsePlatformFilter(t *testing.T) {
	tests := []struct {
		input string
		want  map[string]bool
	}{
		{"", nil},
		{"  ", nil},
		{"UC,CBCA", map[string]bool{"UC": true, "CBCA": true}},
		{" UC , CBCA , ", map[string]bool{"UC": true, "CBCA": true}},
		{"Common", map[string]bool{"Common": true}},
	}

	for _, tt := range tests {
		got := parsePlatformFilter(tt.input)
		if tt.want == nil {
			if got != nil {
				t.Errorf("parsePlatformFilter(%q) = %v, want nil", tt.input, got)
			}
			continue
		}
		if len(got) != len(tt.want) {
			t.Errorf("parsePlatformFilter(%q) = %v, want %v", tt.input, got, tt.want)
			continue
		}
		for k := range tt.want {
			if !got[k] {
				t.Errorf("parsePlatformFilter(%q) missing key %q", tt.input, k)
			}
		}
	}
}

