package namematch

import "strings"

// NewTestMatcher builds a Matcher from a map of lowercase name → unit_id for
// use in tests outside the namematch package. Both exact and normalized maps
// are populated.
func NewTestMatcher(names map[string]string) *Matcher {
	exact := make(map[string]string, len(names))
	normalized := make(map[string]string, len(names))
	for name, unitID := range names {
		exact[strings.ToLower(name)] = unitID
		normalized[Normalize(name)] = unitID
	}
	return &Matcher{
		exact:      exact,
		normalized: normalized,
		alias:      map[string]string{},
		ope6:       map[string]string{},
		ope8:       map[string]string{},
	}
}

